+function createSingleSettlement<T>(params: {
+  resolve: (value: T) => void;
+  reject: (error: unknown) => void;
+  clear: () => void;
+}) {
+  let settled = false;
+  return {
+    isSettled() {
+      return settled;
+    },
+    resolve(value: T) {
+      if (settled) {
+        return;
+      }
+      settled = true;
+      params.clear();
+      params.resolve(value);
+    },
+    reject(error: unknown) {
+      if (settled) {
+        return;
+      }
+      settled = true;
+      params.clear();
+      params.reject(error);
+    },
+  };
+}
